/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel. Handles template
 * rendering, recipient validation, and email delivery. In production the
 * transport layer would integrate with SMTP / SendGrid / AWS SES; the
 * adapter abstracts that behind a pluggable `EmailTransport` interface.
 *
 * ## Usage
 * ```ts
 * const emailAdapter = new EmailAdapter(eventBus);
 * notificationService.registerAdapter(emailAdapter);
 * ```
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSendEvent } from '../events/event-types.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';
import type { NotificationAdapter } from './notification.adapter.js';

// ---------------------------------------------------------------------------
// Email transport abstraction
// ---------------------------------------------------------------------------

/** A rendered email ready for delivery. */
export interface EmailMessage {
  to: string;
  subject: string;
  html: string;
  text: string;
  headers: Record<string, string>;
}

/**
 * Pluggable transport that actually sends the email.
 * Swap in a real SMTP/API implementation for production.
 */
export interface EmailTransport {
  sendMail(message: EmailMessage): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport that records sent messages.
 * Used in development / testing.
 */
export class InMemoryEmailTransport implements EmailTransport {
  private sent: EmailMessage[] = [];

  async sendMail(message: EmailMessage): Promise<{ messageId: string }> {
    const messageId = `msg-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.sent.push(message);
    return { messageId };
  }

  getSentMessages(): EmailMessage[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

// ---------------------------------------------------------------------------
// Template rendering
// ---------------------------------------------------------------------------

/** Template context passed to the renderer. */
interface TemplateContext {
  recipient: string;
  subject: string;
  body: string;
  notificationType: NotificationType;
  priority: NotificationPriority;
  metadata?: Record<string, string>;
}

/** Map of notification type → HTML template function. */
const HTML_TEMPLATES: Record<NotificationType, (ctx: TemplateContext) => string> = {
  order_confirmation: (ctx) =>
    `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
    `<h1 style="color:#2d3748">Order Confirmation</h1>` +
    `<p>${escapeHtml(ctx.body)}</p>` +
    `<p style="color:#718096;font-size:12px">Thank you for your order.</p>` +
    `</div>`,

  order_status_update: (ctx) =>
    `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
    `<h1 style="color:#2d3748">Order Status Update</h1>` +
    `<p>${escapeHtml(ctx.body)}</p>` +
    `</div>`,

  user_welcome: (ctx) =>
    `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
    `<h1 style="color:#2d3748">Welcome!</h1>` +
    `<p>${escapeHtml(ctx.body)}</p>` +
    `</div>`,

  user_update: (ctx) =>
    `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
    `<h1 style="color:#2d3748">Account Update</h1>` +
    `<p>${escapeHtml(ctx.body)}</p>` +
    `</div>`,
};

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Render a notification payload to an HTML email body.
 */
export function renderTemplate(payload: NotificationPayload): string {
  const ctx: TemplateContext = {
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    notificationType: payload.notificationType,
    priority: payload.priority ?? 'normal',
    metadata: payload.metadata,
  };

  const templateFn = HTML_TEMPLATES[payload.notificationType];
  return templateFn(ctx);
}

// ---------------------------------------------------------------------------
// Recipient validation
// ---------------------------------------------------------------------------

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate and normalise an email recipient.
 * Returns the trimmed, lowercased email or null if invalid.
 */
export function resolveRecipient(recipient: string): string | null {
  const normalised = recipient.trim().toLowerCase();
  if (!EMAIL_REGEX.test(normalised)) {
    return null;
  }
  return normalised;
}

// ---------------------------------------------------------------------------
// Priority → header mapping
// ---------------------------------------------------------------------------

function priorityHeaders(priority: NotificationPriority): Record<string, string> {
  switch (priority) {
    case 'high':
      return { 'X-Priority': '1', Importance: 'high' };
    case 'low':
      return { 'X-Priority': '5', Importance: 'low' };
    default:
      return { 'X-Priority': '3', Importance: 'normal' };
  }
}

// ---------------------------------------------------------------------------
// EmailAdapter
// ---------------------------------------------------------------------------

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;

  /** Sent payloads — exposed for testing. */
  private sent: NotificationPayload[] = [];

  constructor(private eventBus: EventBus, transport?: EmailTransport) {
    this.transport = transport ?? new InMemoryEmailTransport();
    this.registerHandler();
  }

  /**
   * Subscribe to notification:send events and handle email-channel payloads.
   */
  private registerHandler(): void {
    this.eventBus.on<NotificationSendEvent>('notification:send', async (event) => {
      if (event.payload.channel === this.channel) {
        await this.send(event.payload);
      }
    });
  }

  /**
   * Deliver an email notification.
   *
   * 1. Validate & resolve the recipient address.
   * 2. Render the notification body using the appropriate template.
   * 3. Build the EmailMessage (including priority headers).
   * 4. Hand off to the configured EmailTransport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Recipient resolution
      const resolvedRecipient = resolveRecipient(payload.recipient);
      if (!resolvedRecipient) {
        const error = `Invalid email recipient: ${payload.recipient}`;
        this.logger.error(error);
        return { success: false, error };
      }

      // 2. Template rendering
      const html = renderTemplate(payload);
      const priority = payload.priority ?? 'normal';

      // 3. Build message
      const message: EmailMessage = {
        to: resolvedRecipient,
        subject: payload.subject,
        html,
        text: payload.body,
        headers: priorityHeaders(priority),
      };

      // 4. Send via transport
      const result = await this.transport.sendMail(message);
      this.logger.info(
        `Email sent to ${resolvedRecipient}: "${payload.subject}" [${result.messageId}]`,
      );

      this.sent.push(payload);
      return { success: true };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown email delivery error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all payloads that were successfully sent (useful for testing).
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sent];
  }

  /**
   * Clear the sent emails list (useful for testing).
   */
  clearSentEmails(): void {
    this.sent = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryEmailTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailAdapter,
  InMemoryEmailTransport,
  renderTemplate,
  resolveRecipient,
} from '../../src/adapters/email.adapter.js';
import type { EmailTransport } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailAdapter', () => {
  let eventBus: EventBus;
  let transport: InMemoryEmailTransport;
  let adapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    transport = new InMemoryEmailTransport();
    adapter = new EmailAdapter(eventBus, transport);
  });

  // -------------------------------------------------------------------------
  // resolveRecipient
  // -------------------------------------------------------------------------

  describe('resolveRecipient', () => {
    it('should accept a valid email address', () => {
      expect(resolveRecipient('alice@example.com')).toBe('alice@example.com');
    });

    it('should normalise to lowercase', () => {
      expect(resolveRecipient('Alice@Example.COM')).toBe('alice@example.com');
    });

    it('should trim whitespace', () => {
      expect(resolveRecipient('  alice@example.com  ')).toBe('alice@example.com');
    });

    it('should reject an empty string', () => {
      expect(resolveRecipient('')).toBeNull();
    });

    it('should reject a string without @', () => {
      expect(resolveRecipient('not-an-email')).toBeNull();
    });

    it('should reject a string with spaces in the middle', () => {
      expect(resolveRecipient('alice @example.com')).toBeNull();
    });
  });

  // -------------------------------------------------------------------------
  // renderTemplate
  // -------------------------------------------------------------------------

  describe('renderTemplate', () => {
    const basePayload: NotificationPayload = {
      recipient: 'alice@example.com',
      subject: 'Test Subject',
      body: 'Test body text',
      notificationType: 'order_confirmation',
      channel: 'email',
      priority: 'normal',
    };

    it('should render order_confirmation template', () => {
      const html = renderTemplate(basePayload);
      expect(html).toContain('Order Confirmation');
      expect(html).toContain('Test body text');
      expect(html).toContain('Thank you for your order');
    });

    it('should render order_status_update template', () => {
      const html = renderTemplate({ ...basePayload, notificationType: 'order_status_update' });
      expect(html).toContain('Order Status Update');
      expect(html).toContain('Test body text');
    });

    it('should render user_welcome template', () => {
      const html = renderTemplate({ ...basePayload, notificationType: 'user_welcome' });
      expect(html).toContain('Welcome!');
    });

    it('should render user_update template', () => {
      const html = renderTemplate({ ...basePayload, notificationType: 'user_update' });
      expect(html).toContain('Account Update');
    });

    it('should escape HTML in body', () => {
      const html = renderTemplate({ ...basePayload, body: '<script>alert("xss")</script>' });
      expect(html).not.toContain('<script>');
      expect(html).toContain('&lt;script&gt;');
    });
  });

  // -------------------------------------------------------------------------
  // send()
  // -------------------------------------------------------------------------

  describe('send', () => {
    const payload: NotificationPayload = {
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      notificationType: 'order_confirmation',
      channel: 'email',
      priority: 'normal',
    };

    it('should send an email via the transport', async () => {
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const messages = transport.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('alice@example.com');
      expect(messages[0]?.subject).toBe('Order Confirmation: order-1');
      expect(messages[0]?.html).toContain('Order Confirmation');
      expect(messages[0]?.text).toBe('Your order has been placed.');
    });

    it('should record the payload in sent list', async () => {
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.recipient).toBe('alice@example.com');
    });

    it('should normalise recipient email', async () => {
      await adapter.send({ ...payload, recipient: '  Alice@Example.COM  ' });

      const messages = transport.getSentMessages();
      expect(messages[0]?.to).toBe('alice@example.com');
    });

    it('should return failure for invalid recipient', async () => {
      const result = await adapter.send({ ...payload, recipient: 'not-an-email' });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email recipient');
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should set high-priority headers', async () => {
      await adapter.send({ ...payload, priority: 'high' });

      const messages = transport.getSentMessages();
      expect(messages[0]?.headers['X-Priority']).toBe('1');
      expect(messages[0]?.headers['Importance']).toBe('high');
    });

    it('should set low-priority headers', async () => {
      await adapter.send({ ...payload, priority: 'low' });

      const messages = transport.getSentMessages();
      expect(messages[0]?.headers['X-Priority']).toBe('5');
      expect(messages[0]?.headers['Importance']).toBe('low');
    });

    it('should set normal-priority headers by default', async () => {
      await adapter.send({ ...payload, priority: undefined });

      const messages = transport.getSentMessages();
      expect(messages[0]?.headers['X-Priority']).toBe('3');
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw new Error('SMTP connection refused');
        },
      };
      const failAdapter = new EmailAdapter(eventBus, failingTransport);

      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });
  });

  // -------------------------------------------------------------------------
  // EventBus integration
  // -------------------------------------------------------------------------

  describe('event bus integration', () => {
    it('should handle notification:send events for email channel', async () => {
      await eventBus.emit({
        type: 'notification:send',
        payload: {
          recipient: 'alice@example.com',
          subject: 'Test',
          body: 'Test body',
          notificationType: 'order_confirmation' as const,
          channel: 'email' as const,
          priority: 'normal' as const,
        },
        timestamp: new Date(),
      });

      expect(adapter.getSentEmails()).toHaveLength(1);
      expect(transport.getSentMessages()).toHaveLength(1);
    });

    it('should ignore notification:send events for other channels', async () => {
      await eventBus.emit({
        type: 'notification:send',
        payload: {
          recipient: 'https://hooks.example.com/webhook',
          subject: 'Test',
          body: 'Test body',
          notificationType: 'order_confirmation' as const,
          channel: 'webhook' as const,
          priority: 'normal' as const,
        },
        timestamp: new Date(),
      });

      expect(adapter.getSentEmails()).toHaveLength(0);
      expect(transport.getSentMessages()).toHaveLength(0);
    });
  });

  // -------------------------------------------------------------------------
  // Utility methods
  // -------------------------------------------------------------------------

  describe('utility methods', () => {
    it('should clear sent emails', async () => {
      await adapter.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        notificationType: 'order_confirmation',
        channel: 'email',
      });

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should expose the transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });
});

