+    });
+
+    it('should normalise to lowercase', () => {
+      expect(resolveRecipient('Alice@Example.COM')).toBe('alice@example.com');
+    });
+
+    it('should trim whitespace', () => {
+      expect(resolveRecipient('  alice@example.com  ')).toBe('alice@example.com');
+    });
+
+    it('should reject an empty string', () => {
+      expect(resolveRecipient('')).toBeNull();
+    });
+
+    it('should reject a string without @', () => {
+      expect(resolveRecipient('not-an-email')).toBeNull();
+    });
+
+    it('should reject a string with spaces in the middle', () => {
+      expect(resolveRecipient('alice @example.com')).toBeNull();
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // renderTemplate
+  // -------------------------------------------------------------------------
+
+  describe('renderTemplate', () => {
+    const basePayload: NotificationPayload = {
+      recipient: 'alice@example.com',
+      subject: 'Test Subject',
+      body: 'Test body text',
+      notificationType: 'order_confirmation',
+      channel: 'email',
+      priority: 'normal',
+    };
+
+    it('should render order_confirmation template', () => {
+      const html = renderTemplate(basePayload);
+      expect(html).toContain('Order Confirmation');
+      expect(html).toContain('Test body text');
+      expect(html).toContain('Thank you for your order');
+    });
+
+    it('should render order_status_update template', () => {
+      const html = renderTemplate({ ...basePayload, notificationType: 'order_status_update' });
+      expect(html).toContain('Order Status Update');
+      expect(html).toContain('Test body text');
+    });
+
+    it('should render user_welcome template', () => {
+      const html = renderTemplate({ ...basePayload, notificationType: 'user_welcome' });
+      expect(html).toContain('Welcome!');
+    });
+
+    it('should render user_update template', () => {
+      const html = renderTemplate({ ...basePayload, notificationType: 'user_update' });
+      expect(html).toContain('Account Update');
+    });
+
+    it('should escape HTML in body', () => {
+      const html = renderTemplate({ ...basePayload, body: '<script>alert("xss")</script>' });
+      expect(html).not.toContain('<script>');
+      expect(html).toContain('&lt;script&gt;');
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // send()
+  // -------------------------------------------------------------------------
+
+  describe('send', () => {
+    const payload: NotificationPayload = {
+      recipient: 'alice@example.com',
+      subject: 'Order Confirmation: order-1',
+      body: 'Your order has been placed.',
+      notificationType: 'order_confirmation',
+      channel: 'email',
+      priority: 'normal',
+    };
+
+    it('should send an email via the transport', async () => {
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const messages = transport.getSentMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]?.to).toBe('alice@example.com');
+      expect(messages[0]?.subject).toBe('Order Confirmation: order-1');
+      expect(messages[0]?.html).toContain('Order Confirmation');
+      expect(messages[0]?.text).toBe('Your order has been placed.');
+    });
+
+    it('should record the payload in sent list', async () => {
+      await adapter.send(payload);
+
+      const sent = adapter.getSentEmails();
